import{_ as d,o as a,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"密契列表","description":"","frontmatter":{},"headers":[],"relativePath":"covenants/list.md","filePath":"zh/covenants/list.md","lastUpdated":1775394001000}'),s={name:"covenants/list.md"};function i(h,t,l,o,n,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="密契列表" tabindex="-1">密契列表 <a class="header-anchor" href="#密契列表" aria-label="Permalink to &quot;密契列表&quot;">​</a></h1><p>密契 (Covenants) 是装备套装系统，每套6件，提供3件套和6件套效果。账号35级解锁。</p><div class="tip custom-block"><p class="custom-block-title">主要属性词条</p><p>暴击率、暴击伤害、伤害强效、银钥充能、狂气回充、界域精通、死亡抵抗、黑印掉落</p></div><h2 id="密契套装一览" tabindex="-1">密契套装一览 <a class="header-anchor" href="#密契套装一览" aria-label="Permalink to &quot;密契套装一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>密契名称</th><th>定位</th><th>效果</th><th>获取方式</th></tr></thead><tbody><tr><td><a href="./scarlet-palpitation.html">猩红之悸 (Scarlet Palpitation)</a></td><td>输出(主C)</td><td>提供双暴(暴击率+暴击伤害)。所有主C通用套装，适用于24、萝坦、尤乌哈希等</td><td>商店兑换/调查兑换/相位兑换</td></tr><tr><td><a href="./scarlet-embrace.html">猩红之拥 (Scarlet Embrace)</a></td><td>辅助/副C</td><td>适合需要主动出牌的辅助角色。不出牌则效果浪费</td><td>沉淀兑换</td></tr><tr><td><a href="./twisted-twins-black.html">扭曲双子·黑 (Twisted Twins Black)</a></td><td>输出/辅助</td><td>将佩戴者的打击卡复制一张加入牌组。适合萝坦、艾继丝</td><td>关卡掉落</td></tr><tr><td><a href="./twisted-twins-white.html">扭曲双子·白 (Twisted Twins White)</a></td><td>坦克/防御</td><td>将佩戴者的防御卡复制一张加入牌组。适合奥吉尔、诺帝拉</td><td>关卡掉落</td></tr><tr><td><a href="./steppe-wolf.html">荒原狼 (Steppe Wolf)</a></td><td>输出/毒伤</td><td>伤害强效+反击/毒素增益。适合莉兹、旺达。v1.4.4后6件套不再需要特定属性</td><td>蔷薇金券商店</td></tr><tr><td><a href="./deus-ex-machina.html">机械降神 (Deus Ex Machina)</a></td><td>辅助</td><td>算力/AP相关效果。辅助角色专用</td><td>关卡掉落</td></tr><tr><td><a href="./returnal-line.html">海归线 (Returnal Line)</a></td><td>深海输出</td><td>力量加成或额外触手攻击次数。深海系角色专用</td><td>关卡掉落</td></tr><tr><td><a href="./burial-ground-whispers.html">埋骨地的絮语 (Burial Ground Whispers)</a></td><td>生存/工具</td><td>6件套：关卡开始+25%死亡抵抗；触发死亡抵抗后获得50狂气</td><td>关卡掉落</td></tr><tr><td><a href="./curse-rabbit.html">诅咒兔 (Curse Rabbit)</a></td><td>治疗</td><td>治疗+护盾增益。适合萨尔瓦多、朵尔、希莱斯特。v1.4.4后6件套不再需要特定属性</td><td>深潜商店</td></tr><tr><td><a href="./distant-feast.html">远方的欢宴 (Distant Feast)</a></td><td>坦克/防御</td><td>大量防御加成。诺帝拉觉醒后每张防御卡可提供200+护盾。v1.4.4后6件套不再需要特定属性</td><td>无光商店</td></tr><tr><td><a href="./unstained-chronicle.html">无垢 (Unstained Chronicle)</a></td><td>辅助</td><td>辅助型角色专用套装</td><td>—</td></tr><tr><td><a href="./organic-form.html">有机形态 (Organic Form)</a></td><td>工具</td><td>6件套(队伍唯一)：探索开始时扣除最多100%死亡抵抗；每扣除1%，佩戴者狂气造成伤害+0.15%</td><td>—</td></tr><tr><td><a href="./antinomy.html">二律背反 (Antinomy)</a></td><td>输出</td><td>6件套(队伍唯一)：狂气上限和超限狂气消耗+20；指令卡暴击率、暴伤、护盾、治疗+20%</td><td>—</td></tr><tr><td><a href="./dream-of-medication.html">入药之梦 (Dream of Medication)</a></td><td>辅助</td><td>6件套(队伍唯一)：战斗结束时黑印获取-8；战斗开始时将佩戴者非打击/非防御指令卡原始版本加入抽牌堆(每种最多1张)</td><td>—</td></tr><tr><td><a href="./ring-of-36-chambers.html">36室之环 (Ring of 36 Chambers)</a></td><td>输出</td><td>6件套(队伍唯一)：银钥上限和银钥技能消耗+200；超限暴击率、暴伤、护盾、治疗+30%</td><td>—</td></tr><tr><td><a href="./further-metamorphosis.html">进化异变 (Further Metamorphosis)</a></td><td>—</td><td>英文攻略中提及的密契套装</td><td>—</td></tr><tr><td><a href="./apocalypse.html">启示录 (Apocalypse)</a></td><td>终局</td><td>终局内容使用的密契套装</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">密契誊抄</p><p>密契誊抄需要3个千面印章+7500蔷薇金券/次。36个千面印章可将密契从+0强化至+12。</p></div>',6)])])}const f=d(s,[["render",i]]);export{p as __pageData,f as default};
